package com.tuapp.clientesimport android.app.NotificationChannelimport android.app.NotificationManagerimport android.content.Contextimport android.os.Buildimport android.view.LayoutInflaterimport android.view.ViewGroupimport android.widget.Buttonimport android.widget.TextViewimport androidx.core.app.NotificationCompatimport androidx.recyclerview.widget.RecyclerViewclass CustomerAdapter(    private var lista: List<Cliente>,    private val context: Context) : RecyclerView.Adapter<CustomerAdapter.ViewHolder>() {    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): ViewHolder {        val view = LayoutInflater.from(parent.context).inflate(R.layout.item_cliente, parent, false)        return ViewHolder(view)    }    override fun onBindViewHolder(holder: ViewHolder, position: Int) {        val cliente = lista[position]        holder.tvNombre.text = cliente.nombre        holder.tvTelefono.text = cliente.telefono        holder.tvEmail.text = cliente.email        holder.btnRecibido.setOnClickListener {            mostrarNotificacion(cliente.nombre)        }    }    override fun getItemCount(): Int = lista.size    fun actualizarLista(nuevaLista: List<Cliente>) {        lista = nuevaLista        notifyDataSetChanged()    }    private fun mostrarNotificacion(nombreCliente: String) {        val notificationManager = context.getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {            val channel = NotificationChannel(                "canal_envios",                "Notificaciones de envíos",                NotificationManager.IMPORTANCE_HIGH            ).apply {                description = "Canal para notificar recepción de envíos"            }            notificationManager.createNotificationChannel(channel)        }        val notification = NotificationCompat.Builder(context, "canal_envios")            .setSmallIcon(android.R.drawable.ic_dialog_info)            .setContentTitle("✅ Envío recibido")            .setContentText("El cliente $nombreCliente ha confirmado la recepción.")            .setPriority(NotificationCompat.PRIORITY_HIGH)            .setAutoCancel(true)            .build()        notificationManager.notify((System.currentTimeMillis() % 100000).toInt(), notification)    }    class ViewHolder(itemView: android.view.View) : RecyclerView.ViewHolder(itemView) {        val tvNombre: TextView = itemView.findViewById(R.id.tvNombre)        val tvTelefono: TextView = itemView.findViewById(R.id.tvTelefono)        val tvEmail: TextView = itemView.findViewById(R.id.tvEmail)        val btnRecibido: Button = itemView.findViewById(R.id.btnRecibido)    }}
